package day3;

public class ArithmeticOperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int num1=5, num2=2;
		System.out.println(num1+num2);
		System.out.println(num2-num1);
		System.out.println(num1*num2);
		System.out.println(num1/num2);
		System.out.println(num1%num2);

	}

}
